import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.ashbyhq.com/reference/introduction";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Ashby API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:ashby",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const ashbyFirewall = {",
    '  name: "ashby",',
    '  description: "Ashby API",',
    "  placeholders: {",
    `    ASHBY_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.ashbyhq.com",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "${{ basic(secrets.ASHBY_TOKEN, ) }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Ashby firewall config...");
  const ts = generateTypeScript();
  writeOutput("ashby", ts, import.meta.dirname);
}
